#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e6+10;int n,a[N];
struct Pair
{
	int p,v;inline Pair(int x=0,int y=0){p=x;v=y;}
	inline bool operator>(const Pair &x)const{return v^x.v?v>x.v:p>x.p;}
}q1[N<<1],q2[N<<1];
inline void Solve()
{
	int h1=1000001,h2=1000001,t1=1000000,t2=1000000;rep(1,n,i)q1[++t1]=Pair(i,a[i]);
	int tmp;while(true)
	{
		if(!(t2-h2+t1-h1)){puts("1");return;}
		int val,idx,v1=q1[h1++].v;
		if(h2>t2||(h1<=t1&&q1[t1]>q2[t2]))val=q1[t1].v,idx=q1[t1--].p;
		else val=q2[t2].v,idx=q2[t2--].p;Pair cur=Pair(idx,val-v1);
		if(h1>t1||q1[h1]>cur)
		{
			tmp=t2-h2+t1-h1+4;int tot=0;
			while(++tot)
			{
				if(t1-h1+t2-h2+3==2){tot&1?0:--tmp;break;}int val,idx;
				if(h2>t2||(h1<=t1&&q1[t1]>q2[t2]))val=q1[t1].v,idx=q1[t1--].p;
				else val=q2[t2].v,idx=q2[t2--].p;cur=Pair(idx,val-cur.v);
				if((h1<=t1&&cur>q1[h1])||(h2<=t2&&cur>q2[h2])){tot&1?0:--tmp;break;}
			}
			printf("%d\n",tmp);return;
		}else q2[--h2]=cur;
	}
}
int main()
{
	int T=read();n=read();rep(1,n,i)a[i]=read();Solve();
	while(--T){int k=read();rep(1,k,i){int x=read();a[x]=read();}Solve();}return 0;
}
